				break
			}
			dispatch.Assigns[ind].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[ind].GenRoute()
			if dispatch.Assigns[ind].Cost > 0 {
				flag = false
				break
			}
			dispatch.Assigns[ind].RemoveShip(total_ship + jj)
			dispatch.Assigns[ind].GenRoute()
